{% set doc = frappe.get_doc("InductOne Configuration Order", doc.name) %}

<div class="por-print">

<style>
    .por-print,
    .por-print * {
        font-family: Arial, Helvetica, sans-serif !important;
    }

    .por-print {
        color: #101828;
        font-size: 11px;
        line-height: 1.6;
        max-width: 100%;
    }

    .por-print * {
        box-sizing: border-box;
    }

    /* ---------- HEADER ---------- */

    .por-header {
        display: table;
        width: 100%;
        border-bottom: 3px solid #1794CE;
        padding-bottom: 14px;
        margin-bottom: 24px;
    }

    .por-header-left,
    .por-header-right {
        display: table-cell;
        vertical-align: middle;
    }

    .por-header-left {
        width: 50%;
    }

    .por-header-right {
        width: 50%;
        text-align: right;
    }

    .por-logo {
        height: 48px;
        width: auto;
    }

    .por-doc-type {
        font-size: 22px;
        font-weight: 700;
        letter-spacing: 3px;
        text-transform: uppercase;
        color: #3C4447;
        margin: 0;
        line-height: 1;
    }

    .por-doc-number {
        font-size: 12px;
        color: #1794CE;
        font-weight: 600;
        margin-top: 6px;
        letter-spacing: 0.5px;
    }

    .por-doc-subtitle {
        font-size: 10px;
        color: #667085;
        font-weight: 400;
        margin-top: 4px;
        letter-spacing: 0.3px;
    }

    .por-status-badge {
        display: inline-block;
        background: #1794CE;
        color: #FFFFFF;
        font-size: 10px;
        font-weight: 700;
        letter-spacing: 1.2px;
        padding: 4px 12px;
        border-radius: 3px;
        margin-top: 8px;
        text-transform: uppercase;
    }

    /* ---------- SYSTEM SERIAL BANNER ---------- */

    .por-serial-banner {
        background: #FEF3C7;
        border: 2px solid #F59E0B;
        border-radius: 4px;
        padding: 14px 18px;
        margin-bottom: 22px;
        display: table;
        width: 100%;
    }

    .por-serial-banner-label {
        display: table-cell;
        vertical-align: middle;
        width: 55%;
        font-size: 10px;
        font-weight: 700;
        text-transform: uppercase;
        letter-spacing: 1.5px;
        color: #92400E;
    }

    .por-serial-banner-value {
        display: table-cell;
        vertical-align: middle;
        text-align: right;
        font-size: 22px;
        font-weight: 800;
        color: #92400E;
        letter-spacing: 2px;
    }

    .por-serial-banner-missing {
        color: #B91C1C;
        font-style: italic;
        font-weight: 600;
        font-size: 14px;
        letter-spacing: 0;
    }

    /* ---------- SECTION ---------- */

    .por-section {
        font-size: 10px;
        font-weight: 700;
        text-transform: uppercase;
        letter-spacing: 2px;
        color: #1794CE;
        margin: 24px 0 12px 0;
        padding-bottom: 6px;
        border-bottom: 1px solid #D0D5DD;
    }

    /* ---------- META GRID ---------- */

    .por-meta-grid {
        width: 100%;
        margin-bottom: 20px;
        border-collapse: collapse;
    }

    .por-meta-grid td {
        width: 25%;
        padding: 10px 14px;
        vertical-align: top;
        border-bottom: 1px solid #EAECF0;
    }

    .por-meta-grid td:not(:last-child) {
        border-right: 1px solid #EAECF0;
    }

    .por-meta-label {
        font-size: 9px;
        font-weight: 700;
        text-transform: uppercase;
        letter-spacing: 1.2px;
        color: #1794CE;
        margin-bottom: 3px;
    }

    .por-meta-value {
        font-size: 12px;
        font-weight: 600;
        color: #101828;
    }

    .por-meta-value.serial-highlight {
        color: #92400E;
        font-weight: 800;
        letter-spacing: 1px;
    }

    /* ---------- CONTENT CARDS ---------- */

    .por-card {
        border: 1px solid #EAECF0;
        border-radius: 4px;
        margin-bottom: 14px;
        page-break-inside: avoid;
    }

    .por-card-header {
        background: #F9FAFB;
        border-bottom: 1px solid #EAECF0;
        border-left: 4px solid #1794CE;
        padding: 10px 14px;
        font-size: 11px;
        font-weight: 700;
        color: #101828;
    }

    .por-card-header.serial-card-header {
        background: #FEF3C7;
        border-left-color: #F59E0B;
        color: #92400E;
    }

    .por-card-body {
        padding: 12px 16px;
        color: #475467;
        font-size: 10px;
        line-height: 1.65;
    }

    /* ---------- STEP DETAIL ---------- */

    .por-step-detail {
        width: 100%;
        font-size: 10px;
    }

    .por-step-row {
        display: flex;
        align-items: baseline;
        border-bottom: 1px solid #F2F4F7;
        padding: 8px 0;
    }

    .por-step-row:last-child {
        border-bottom: none;
    }

    .por-step-label {
        flex: 0 0 70px;
        padding-right: 12px;
        font-weight: 700;
        text-transform: uppercase;
        letter-spacing: 0.8px;
        color: #1794CE;
        font-size: 9px;
        line-height: 1.4;
        white-space: nowrap;
    }

    .por-step-value {
        flex: 1;
        color: #344054;
        font-size: 10px;
        line-height: 1.4;
    }

    .por-step-value.caution {
        color: #A32D2D;
        font-weight: 600;
    }

    .por-step-value .serial-inline {
        background: #FEF3C7;
        color: #92400E;
        font-weight: 800;
        padding: 2px 8px;
        border-radius: 3px;
        letter-spacing: 1px;
    }

    /* ---------- TABLE ---------- */

    .por-table {
        width: 100%;
        border-collapse: collapse;
        table-layout: fixed;
        margin-bottom: 16px;
        font-size: 10px;
    }

    .por-table thead th {
        background: #3C4447;
        color: #FFFFFF;
        font-weight: 600;
        text-transform: uppercase;
        font-size: 9px;
        letter-spacing: 1px;
        padding: 9px 8px;
        text-align: left;
        border: none;
    }

    .por-table tbody td {
        padding: 10px 8px;
        border-bottom: 1px solid #EAECF0;
        vertical-align: top;
        color: #344054;
    }

    .por-table tbody tr:nth-child(even) td {
        background: #F9FAFB;
    }

    /* ---------- CHECKLIST ---------- */

    .por-checklist {
        list-style: none;
        margin: 0;
        padding: 0;
    }

    .por-checklist li {
        padding: 8px 0 8px 28px;
        border-bottom: 1px dashed #EAECF0;
        color: #344054;
        position: relative;
        font-size: 10px;
        line-height: 1.5;
    }

    .por-checklist li:last-child {
        border-bottom: none;
    }

    .por-checklist li:before {
        content: "";
        position: absolute;
        left: 0;
        top: 9px;
        width: 14px;
        height: 14px;
        border: 1.5px solid #98A2B3;
        border-radius: 2px;
        background: #FFFFFF;
    }

    /* ---------- FOOTER ---------- */

    .por-footer {
        margin-top: 30px;
        padding-top: 12px;
        border-top: 2px solid #1794CE;
        text-align: center;
        font-size: 9px;
        color: #667085;
        letter-spacing: 0.5px;
    }

    .por-footer .tagline {
        color: #1794CE;
        font-weight: 700;
        text-transform: uppercase;
        letter-spacing: 2px;
        margin-bottom: 4px;
    }

    .por-footer .footer-meta {
        display: table;
        width: 100%;
        margin-top: 6px;
    }

    .por-footer .footer-meta span {
        display: table-cell;
        width: 50%;
    }

    .por-footer .footer-meta .left {
        text-align: left;
    }

    .por-footer .footer-meta .right {
        text-align: right;
    }

    /* ---------- PRINT TWEAKS ---------- */

    @media print {
        .por-serial-banner,
        .por-card-header.serial-card-header,
        .por-step-value .serial-inline,
        .por-status-badge,
        .por-table thead th,
        .por-table tbody tr:nth-child(even) td {
            -webkit-print-color-adjust: exact;
            print-color-adjust: exact;
        }
    }

</style>

<!-- HEADER -->

<div class="por-header">
    <div class="por-header-left">
        <img src="/files/image.png" alt="Plus One Robotics" class="por-logo" />
    </div>

    <div class="por-header-right">
        <div class="por-doc-type">Builder Instructions</div>
        <div class="por-doc-number">{{ doc.inductone_build or doc.name }}</div>
        <div class="por-doc-subtitle">InductOne · Builder Release Package Instructions</div>
        <div>
            <span class="por-status-badge">Builder Instructions</span>
        </div>
    </div>
</div>

<!-- SYSTEM SERIAL BANNER -->

<div class="por-serial-banner">
    <div class="por-serial-banner-label">
        System Serial — Apply to this unit
    </div>
    <div class="por-serial-banner-value">
        {% if doc.system_serial %}
            {{ doc.system_serial }}
        {% else %}
            <span class="por-serial-banner-missing">NOT YET ALLOCATED</span>
        {% endif %}
    </div>
</div>

<!-- BUILD IDENTIFIER -->

<table class="por-meta-grid">
    <tr>
        <td>
            <div class="por-meta-label">System Serial</div>
            <div class="por-meta-value serial-highlight">{{ doc.system_serial or "—" }}</div>
        </td>

        <td>
            <div class="por-meta-label">InductOne Build</div>
            <div class="por-meta-value">{{ doc.inductone_build or "—" }}</div>
        </td>

        <td>
            <div class="por-meta-label">Configuration Order</div>
            <div class="por-meta-value">{{ doc.name }}</div>
        </td>

        <td>
            <div class="por-meta-label">Builder</div>
            <div class="por-meta-value">{{ doc.builder_supplier or "—" }}</div>
        </td>
    </tr>
</table>

<!-- PACKAGE CONTENTS -->

<div class="por-section">Release Package Contents</div>

<table class="por-table">
    <thead>
        <tr>
            <th style="width: 32%;">Document</th>
            <th>Purpose</th>
        </tr>
    </thead>

    <tbody>
        <tr>
            <td><strong>Configuration Order PDF</strong></td>
            <td>Formal release record defining the exact configured build.</td>
        </tr>

        <tr>
            <td><strong>BOM Export Package ZIP</strong></td>
            <td>Part drawings and manufacturing files organized by item code.</td>
        </tr>

        <tr>
            <td><strong>Flat BOM CSV</strong></td>
            <td>Rolled-up procurement and assembly parts list.</td>
        </tr>

        <tr>
            <td><strong>Builder Serial Capture Workbook</strong></td>
            <td>Workbook for recording required serialized components during fabrication.</td>
        </tr>

        <tr>
            <td><strong>Builder Release Manifest</strong></td>
            <td>System-generated release evidence showing package contents and timestamps.</td>
        </tr>
    </tbody>
</table>

<!-- BUILDER RESPONSIBILITIES -->

<div class="por-section">Builder Responsibilities</div>

<div class="por-card">
    <div class="por-card-header">1. Acknowledge Receipt</div>

    <div class="por-card-body">
        <div class="por-step-detail">

            <div class="por-step-row">
                <div class="por-step-label">When</div>
                <div class="por-step-value">
                    Before fabrication begins.
                </div>
            </div>

            <div class="por-step-row">
                <div class="por-step-label">Action</div>
                <div class="por-step-value">
                    Sign the Acknowledgment block on the last page of the Configuration Order PDF.
                </div>
            </div>

            <div class="por-step-row">
                <div class="por-step-label">Return</div>
                <div class="por-step-value">
                    Signed CO PDF to your Plus One Operations point of contact.
                </div>
            </div>

            <div class="por-step-row">
                <div class="por-step-label">Result</div>
                <div class="por-step-value">
                    Build status moves to <em>Awaiting Completion</em>. You may begin fabrication.
                </div>
            </div>

        </div>
    </div>
</div>

<div class="por-card">
    <div class="por-card-header serial-card-header">
        2. Apply System Serial
        {% if doc.system_serial %}
            ({{ doc.system_serial }})
        {% endif %}
    </div>

    <div class="por-card-body">
        <div class="por-step-detail">

            <div class="por-step-row">
                <div class="por-step-label">When</div>
                <div class="por-step-value">
                    During fabrication, before final assembly is closed.
                </div>
            </div>

            <div class="por-step-row">
                <div class="por-step-label">Action</div>
                <div class="por-step-value">
                    {% if doc.system_serial %}
                        Apply the assigned system serial <span class="serial-inline">{{ doc.system_serial }}</span> to the unit by permanent label, in the location specified by Plus One Operations.
                    {% else %}
                        Apply the assigned system serial (TO BE PROVIDED) to the unit by permanent label, in the location specified by Plus One Operations.
                    {% endif %}
                </div>
            </div>

            <div class="por-step-row">
                <div class="por-step-label">Caution</div>
                <div class="por-step-value caution">
                    This serial uniquely identifies this physical unit for its entire service life. Do NOT use a different serial, alter the assigned serial, or apply it to a different unit. If the serial is not legible after application, contact Plus One Operations before proceeding.
                </div>
            </div>

            <div class="por-step-row">
                <div class="por-step-label">Result</div>
                <div class="por-step-value">
                    Unit is permanently identified. This serial will be the record of this unit in Plus One systems forever.
                </div>
            </div>

        </div>
    </div>
</div>

<div class="por-card">
    <div class="por-card-header">3. Build to the Configuration Order</div>

    <div class="por-card-body">
        <div class="por-step-detail">

            <div class="por-step-row">
                <div class="por-step-label">When</div>
                <div class="por-step-value">
                    During fabrication.
                </div>
            </div>

            <div class="por-step-row">
                <div class="por-step-label">Action</div>
                <div class="por-step-value">
                    Fabricate exactly to the configured options listed in the Configuration Order PDF and to the drawings in the BOM Export Package.
                </div>
            </div>

            <div class="por-step-row">
                <div class="por-step-label">Caution</div>
                <div class="por-step-value caution">
                    Do NOT silently substitute parts, omit features, or alter assemblies. If a deviation is required (substitute part, unavailable material, missing drawing, fabrication change), contact Plus One Operations <strong>before</strong> making the change.
                </div>
            </div>

        </div>
    </div>
</div>

<div class="por-card">
    <div class="por-card-header">4. Record Serialized Components</div>

    <div class="por-card-body">
        <div class="por-step-detail">

            <div class="por-step-row">
                <div class="por-step-label">When</div>
                <div class="por-step-value">
                    As serialized components are installed during fabrication.
                </div>
            </div>

            <div class="por-step-row">
                <div class="por-step-label">Action</div>
                <div class="por-step-value">
                    Fill in serial numbers in the Builder Serial Capture Workbook for every item the workbook lists.
                </div>
            </div>

            <div class="por-step-row">
                <div class="por-step-label">Result</div>
                <div class="por-step-value">
                    A complete record of every serialized component installed in this build, traceable to this Configuration Order.
                </div>
            </div>

        </div>
    </div>
</div>

<div class="por-card">
    <div class="por-card-header">5. Submit Completion Package</div>

    <div class="por-card-body">
        <div class="por-step-detail">

            <div class="por-step-row">
                <div class="por-step-label">When</div>
                <div class="por-step-value">
                    When fabrication is complete.
                </div>
            </div>

            <div class="por-step-row">
                <div class="por-step-label">Action</div>
                <div class="por-step-value">
                    Return the completed Builder Serial Capture Workbook and any deviation notes to your Plus One Operations point of contact.
                </div>
            </div>

            <div class="por-step-row">
                <div class="por-step-label">Result</div>
                <div class="por-step-value">
                    Plus One reviews the submission. Once accepted, the build is closed and an immutable As-Built Record is created.
                </div>
            </div>

        </div>
    </div>
</div>

<!-- COMPLETION CHECKLIST -->

<div class="por-section">Completion Checklist</div>

<div class="por-card">
    <div class="por-card-body">
        <p style="margin-top:0;margin-bottom:10px;color:#475467;">
            Before submitting completion, confirm each item below:
        </p>

        <ul class="por-checklist">
            <li>
                System serial
                {% if doc.system_serial %}
                    <span class="serial-inline">{{ doc.system_serial }}</span>
                {% endif %}
                has been applied to the unit and is legible.
            </li>
            <li>Builder Serial Capture Workbook is filled in for every required item.</li>
            <li>All deviations and substitutions made during fabrication are documented in writing.</li>
            <li>Any other completion evidence required by your contract is prepared.</li>
            <li>Completion package is sent to your Plus One Operations point of contact.</li>
        </ul>
    </div>
</div>

<!-- QUESTIONS -->

<div class="por-section">Questions & Escalation</div>

<div class="por-card">
    <div class="por-card-body">
        Contact your assigned Plus One Robotics Operations point of contact for any questions regarding the release package, fabrication requirements, or build execution.
        <br><br>
        Escalation Contact: <strong>michael.king@plusonerobotics.com</strong>
    </div>
</div>

<!-- FOOTER -->

<div class="por-footer">
    <div class="tagline">Robots work. People rule.</div>

    Plus One Robotics · Confidential and Proprietary

    <div class="footer-meta">
        <span class="left">
            {{ doc.inductone_build or doc.name }}
            {% if doc.system_serial %}
                &nbsp;·&nbsp; {{ doc.system_serial }}
            {% endif %}
        </span>

        <span class="right">
            Generated {{ frappe.utils.now() }}
        </span>
    </div>
</div>

</div>

