        letter-spacing: 2px;
    }
    .por-print .por-serial-banner-missing {
        color: #B91C1C;
        font-style: italic;
        font-weight: 600;
        font-size: 14px;
        letter-spacing: 0;
    }

    /* ---------- SECTION HEADER ---------- */
    .por-print .por-section {
        font-size: 10px;
        font-weight: 700;
        text-transform: uppercase;
        letter-spacing: 2px;
        color: #1794CE;
        margin: 22px 0 10px 0;
        padding-bottom: 6px;
        border-bottom: 1px solid #D0D5DD;
    }

    /* ---------- META GRID ---------- */
    .por-print .por-meta-grid {
        width: 100%;
        margin-bottom: 20px;
        border-collapse: collapse;
    }
    .por-print .por-meta-grid td {
        width: 50%;
        padding: 10px 14px;
        vertical-align: top;
        border-bottom: 1px solid #EAECF0;
    }
    .por-print .por-meta-grid td:first-child {
        border-right: 1px solid #EAECF0;
    }
    .por-print .por-meta-grid .por-meta-label {
        font-size: 9px;
        font-weight: 700;
        text-transform: uppercase;
        letter-spacing: 1.2px;
        color: #1794CE;
        margin-bottom: 3px;
    }
    .por-print .por-meta-grid .por-meta-value {
        font-size: 12px;
        font-weight: 600;
        color: #101828;
        word-wrap: break-word;
    }

    /* ---------- OPTION CARDS ---------- */
    .por-print .por-option-card {
        border: 1px solid #EAECF0;
        border-radius: 4px;
        margin-bottom: 10px;
        page-break-inside: avoid;
    }
    .por-print .por-option-header {
        display: table;
        width: 100%;
        background: #F9FAFB;
        border-bottom: 1px solid #EAECF0;
        border-left: 4px solid #1794CE;
        border-radius: 4px 4px 0 0;
        padding: 8px 12px;
    }
    .por-print .por-option-code {
        display: table-cell;
        font-size: 11px;
        font-weight: 700;
        color: #101828;
        width: 22%;
        vertical-align: middle;
    }
    .por-print .por-option-name {
        display: table-cell;
        font-size: 11px;
        font-weight: 600;
        color: #344054;
        vertical-align: middle;
    }
    .por-print .por-option-category {
        display: table-cell;
        font-size: 9px;
        color: #667085;
        text-transform: uppercase;
        letter-spacing: 1px;
        text-align: right;
        width: 25%;
        vertical-align: middle;
    }
    .por-print .por-option-notes {
        padding: 10px 14px;
        font-size: 10px;
        color: #475467;
        white-space: pre-wrap;
        line-height: 1.55;
    }
    .por-print .por-option-notes-empty {
        padding: 10px 14px;
        font-size: 10px;
        color: #98A2B3;
        font-style: italic;
    }
    .por-print .por-empty-state {
        font-size: 10px;
        color: #667085;
        margin-bottom: 16px;
        padding: 12px;
        background: #F9FAFB;
        border-radius: 4px;
        border: 1px solid #EAECF0;
        font-style: italic;
    }

    /* ---------- DOCUMENT INDEX TABLE ---------- */
    .por-print .por-table {
        width: 100%;
        border-collapse: collapse;
        table-layout: fixed;
        margin-bottom: 16px;
        font-size: 10px;
    }
    .por-print .por-table thead th {
        background: #3C4447;
        color: #FFFFFF;
        font-weight: 600;
        text-transform: uppercase;
        font-size: 9px;
        letter-spacing: 1px;
        padding: 9px 8px;
        text-align: left;
        border: none;
    }
    .por-print .por-table tbody td {
        padding: 8px;
        border-bottom: 1px solid #EAECF0;
        vertical-align: top;
        color: #344054;
        word-wrap: break-word;
        overflow-wrap: break-word;
    }
    .por-print .por-table tbody tr:nth-child(even) td {
        background: #F9FAFB;
    }
    .por-print .por-table .text-center { text-align: center; }
    .por-print .por-table .file-url {
        font-size: 9px;
        color: #1794CE;
    }
    .por-print .por-table .small-meta {
        font-size: 9px;
        color: #667085;
    }

    /* ---------- BADGES ---------- */
    .por-print .por-badge {
        display: inline-block;
        font-size: 9px;
        font-weight: 700;
        padding: 2px 8px;
        border-radius: 3px;
        text-transform: uppercase;
        letter-spacing: 0.5px;
    }
    .por-print .por-badge-yes {
        background: #E6F4EA;
        color: #027A48;
    }
    .por-print .por-badge-no {
        background: #EAECF0;
        color: #667085;
    }

    /* ---------- NOTES BOX ---------- */
    .por-print .por-notes {
        background: #FFFFFF;
        border: 1px solid #EAECF0;
        border-radius: 4px;
        padding: 12px 16px;
        color: #344054;
        font-size: 11px;
        margin-bottom: 16px;
        white-space: pre-wrap;
    }

    /* ---------- SIGNATURE BLOCK ---------- */
    .por-print .por-signature {
        display: table;
        width: 100%;
        margin-top: 28px;
        border-collapse: separate;
        border-spacing: 24px 0;
    }
    .por-print .por-sig-cell {
        display: table-cell;
        width: 50%;
        vertical-align: bottom;
    }
    .por-print .por-sig-label {
        font-size: 9px;
        font-weight: 700;
        text-transform: uppercase;
        letter-spacing: 1.2px;
        color: #1794CE;
        margin-bottom: 4px;
    }
    .por-print .por-sig-line {
        border-top: 1px solid #3C4447;
        padding-top: 5px;
        font-size: 9px;
        color: #667085;
        margin-top: 36px;
    }
    .por-print .por-sig-line-second {
        border-top: 1px solid #3C4447;
        padding-top: 5px;
        font-size: 9px;
        color: #667085;
        margin-top: 24px;
    }

    /* ---------- FOOTER ---------- */
    .por-print .por-footer {
        margin-top: 30px;
        padding-top: 12px;
        border-top: 2px solid #1794CE;
        text-align: center;
        font-size: 9px;
        color: #667085;
        letter-spacing: 0.5px;
    }
    .por-print .por-footer .tagline {
        color: #1794CE;
        font-weight: 700;
        text-transform: uppercase;
        letter-spacing: 2px;
        margin-bottom: 4px;
    }
    .por-print .por-footer .footer-meta {
        display: table;
        width: 100%;
        margin-top: 6px;
    }
    .por-print .por-footer .footer-meta span {
        display: table-cell;
        width: 50%;
    }
    .por-print .por-footer .footer-meta .left { text-align: left; }
    .por-print .por-footer .footer-meta .right { text-align: right; }

    /* ---------- PRINT TWEAKS ---------- */
    @media print {
        .por-print .por-table thead th,
        .por-print .por-status-badge,
        .por-print .por-option-header,
        .por-print .por-table tbody tr:nth-child(even) td,
        .por-print .por-badge-yes,
        .por-print .por-badge-no,
        .por-print .por-empty-state,
        .por-print .por-serial-banner {
            -webkit-print-color-adjust: exact;
            print-color-adjust: exact;
        }
    }
</style>

<!-- ============ HEADER ============ -->
<div class="por-header">
    <div class="por-header-left">
        <img src="/files/image.png" alt="Plus One Robotics" class="por-logo" />
    </div>
    <div class="por-header-right">
        <div class="por-doc-type">Configuration Order</div>
        <div class="por-doc-number">{{ doc.name }}</div>
        <div class="por-doc-subtitle">InductOne · Builder Release Package</div>
        <div><span class="por-status-badge">Released to Builder</span></div>
    </div>
</div>

<!-- ============ SYSTEM SERIAL BANNER ============ -->
<div class="por-serial-banner">
    <div class="por-serial-banner-label">
        System Serial — Apply to this unit
    </div>
    <div class="por-serial-banner-value">
        {% if doc.system_serial %}
            {{ doc.system_serial }}
        {% else %}
            <span class="por-serial-banner-missing">NOT YET ALLOCATED</span>
        {% endif %}
    </div>
</div>

<!-- ============ IDENTITY BLOCK ============ -->
<div class="por-section">Order Identity</div>
<table class="por-meta-grid">
    <tr>
        <td>
            <div class="por-meta-label">Configuration Order</div>
            <div class="por-meta-value">{{ doc.name }}</div>
        </td>
        <td>
            <div class="por-meta-label">Revision</div>
            <div class="por-meta-value">{{ doc.config_order_rev or "—" }}</div>
        </td>
    </tr>
    <tr>
        <td>
            <div class="por-meta-label">System Serial</div>
            <div class="por-meta-value">{{ doc.system_serial or "—" }}</div>
        </td>
        <td>
            <div class="por-meta-label">InductOne Build</div>
            <div class="por-meta-value">{{ doc.inductone_build or "—" }}</div>
        </td>
    </tr>
    <tr>
        <td>
            <div class="por-meta-label">Sales Order</div>
            <div class="por-meta-value">{{ doc.sales_order or "—" }}</div>
        </td>
        <td>
            <div class="por-meta-label">Customer / Project</div>
            <div class="por-meta-value">{{ doc.customer_project_label or "—" }}</div>
        </td>
    </tr>
    <tr>
        <td>
            <div class="por-meta-label">Orientation</div>
            <div class="por-meta-value">{{ doc.orientation or "—" }}</div>
        </td>
        <td>
            <div class="por-meta-label">Top Item</div>
            <div class="por-meta-value">{{ doc.top_item or "—" }}</div>
        </td>
    </tr>
    <tr>
        <td>
            <div class="por-meta-label">Top BOM</div>
            <div class="por-meta-value">{{ doc.top_bom or "—" }}</div>
        </td>
        <td>
            <div class="por-meta-label">Configured Snapshot</div>
            <div class="por-meta-value">{{ doc.snapshot or "—" }}</div>
        </td>
    </tr>
    <tr>
        <td>
            <div class="por-meta-label">Flat BOM Status</div>
            <div class="por-meta-value">{{ doc.flat_bom_status or "—" }}</div>
        </td>
        <td>
            <div class="por-meta-label">Sales Order Item IDX</div>
            <div class="por-meta-value">{{ doc.sales_order_item_idx or "—" }}</div>
        </td>
    </tr>
    <tr>
        <td>
            <div class="por-meta-label">Generated At</div>
            <div class="por-meta-value">{{ doc.generated_at or "—" }}</div>
        </td>
        <td>
            <div class="por-meta-label">Generated By</div>
            <div class="por-meta-value">{{ doc.generated_by or "—" }}</div>
        </td>
    </tr>
</table>

<!-- ============ BUILDER BLOCK ============ -->
<div class="por-section">Builder</div>
<table class="por-meta-grid">
    <tr>
        <td>
            <div class="por-meta-label">Builder (Supplier)</div>
            <div class="por-meta-value">{{ doc.builder_supplier or "—" }}</div>
        </td>
        <td>
            <div class="por-meta-label">Builder Tranche</div>
            <div class="por-meta-value">{{ doc.builder_tranche or "—" }}</div>
        </td>
