</table>

<!-- ============ CONFIGURATION OPTIONS ============ -->
<!-- ============ CONFIGURATION OPTIONS ============ -->
<!-- Self-contained: all styles inline. Replaces the entire Configuration -->
<!-- Options block. Does not depend on any CSS in the <style> block.        -->

<div class="por-section">Configuration Options</div>

{% if doc.selected_options %}
    {% for o in doc.selected_options | sort(attribute='option_category') %}
        <div style="border:1px solid #EAECF0;border-radius:4px;margin-bottom:10px;page-break-inside:avoid;">

            <div style="background:#F9FAFB;border-bottom:1px solid #EAECF0;border-left:4px solid #1794CE;border-radius:4px 4px 0 0;padding:8px 12px;">
                <span style="font-size:11px;font-weight:700;color:#101828;">{{ o.option_code or "—" }}</span>
                <span style="font-size:11px;font-weight:600;color:#344054;margin-left:10px;">{{ o.option_name or "—" }}</span>
                <span style="font-size:9px;color:#667085;text-transform:uppercase;letter-spacing:1px;float:right;">{{ o.option_category or "" }}</span>
            </div>

            {% if o.builder_description %}
                {% set _eff = o.builder_description.split('Configuration effect:') %}
                <div style="padding:14px 16px;">

                    <div style="font-size:11px;color:#344054;line-height:1.7;white-space:pre-wrap;margin-bottom:14px;padding-bottom:14px;border-bottom:1px solid #F2F4F7;">{{ _eff[0] | trim }}</div>

                    {% if _eff | length > 1 %}
                        {% set _notes = _eff[1].split('Notes:') %}

                        <div style="margin-bottom:12px;">
                            <div style="font-size:8.5px;font-weight:700;text-transform:uppercase;letter-spacing:1px;color:#1794CE;margin-bottom:5px;">Configuration Effect</div>
                            <div style="font-size:10px;color:#475467;line-height:1.6;white-space:pre-wrap;padding-left:12px;border-left:2px solid #1794CE;">{{ _notes[0] | trim }}</div>
                        </div>

                        {% if _notes | length > 1 %}
                        <div>
                            <div style="font-size:8.5px;font-weight:700;text-transform:uppercase;letter-spacing:1px;color:#1794CE;margin-bottom:5px;">Notes</div>
                            <div style="font-size:10px;color:#475467;line-height:1.6;white-space:pre-wrap;padding-left:12px;border-left:2px solid #D0D5DD;">{{ _notes[1] | trim }}</div>
                        </div>
                        {% endif %}

                    {% endif %}
                </div>
            {% else %}
                <div style="padding:10px 14px;font-size:10px;color:#98A2B3;font-style:italic;">No builder description provided.</div>
            {% endif %}

        </div>
    {% endfor %}
{% else %}
    <div style="font-size:10px;color:#667085;margin-bottom:16px;padding:12px;background:#F9FAFB;border-radius:4px;border:1px solid #EAECF0;font-style:italic;">No options selected — standard baseline build.</div>
{% endif %}

<!-- ============ DOCUMENT INDEX ============ -->
{% if doc.documents %}
<div class="por-section">Document Index — Release Package</div>
<table class="por-table">
    <colgroup>
        <col style="width: 24%;">
        <col style="width: 13%;">
        <col style="width: 17%;">
        <col style="width: 9%;">
        <col style="width: 22%;">
        <col style="width: 15%;">
    </colgroup>
    <thead>
        <tr>
            <th>Title</th>
            <th>Source Type</th>
            <th>Source</th>
            <th class="text-center">Required</th>
            <th>File</th>
            <th>Notes</th>
        </tr>
    </thead>
    <tbody>
        {% for d in doc.documents | sort(attribute='sort_order') %}
        <tr>
            <td><strong>{{ d.doc_title or "—" }}</strong></td>
            <td>{{ d.source_type or "—" }}</td>
            <td class="small-meta">{{ d.source_name or "—" }}</td>
            <td class="text-center">
                {% if d.required == "YES" %}
                    <span class="por-badge por-badge-yes">Yes</span>
                {% else %}
                    <span class="por-badge por-badge-no">No</span>
                {% endif %}
            </td>
            <td class="file-url">{{ d.file_url or "—" }}</td>
            <td class="small-meta">{{ d.small_text_vtsj or "" }}</td>
        </tr>
        {% endfor %}
    </tbody>
</table>
{% endif %}

<!-- ============ BUILDER NOTES ============ -->
{% if doc.builder_notes %}
<div class="por-section">Builder Notes</div>
<div class="por-notes">{{ doc.builder_notes }}</div>
{% endif %}

<!-- ============ SIGNATURE BLOCK ============ -->
<div class="por-section">Release Authorization &amp; Builder Acknowledgment</div>
<div class="por-signature">
    <div class="por-sig-cell">
        <div class="por-sig-label">Released By — Plus One Robotics</div>
        <div class="por-sig-line">Name &amp; Signature</div>
        <div class="por-sig-line-second">Date</div>
    </div>
    <div class="por-sig-cell">
        <div class="por-sig-label">Acknowledged By — Builder</div>
        <div class="por-sig-line">Name &amp; Signature</div>
        <div class="por-sig-line-second">Date</div>
    </div>
</div>

<!-- ============ FOOTER ============ -->
<div class="por-footer">
    <div class="tagline">Robots work. People rule.</div>
    Plus One Robotics &nbsp;·&nbsp; Confidential and Proprietary
    <div class="footer-meta">
        <span class="left">{{ doc.name }} &nbsp;·&nbsp; Rev {{ doc.config_order_rev or "1" }} &nbsp;·&nbsp; {{ doc.system_serial or "" }}</span>
        <span class="right">Generated {{ doc.generated_at or "" }}</span>
    </div>
</div>

</div>
